<Tooltip content="Help text here" placement="top">
  <button>Hover me</button>
</Tooltip>

/* ── Info icon trigger (label) ── */
<label class="dt-input-label">
  Field label
  <Tooltip content="This field controls X behavior.">
    <InfoFilledIcon />
  </Tooltip>
</label>

/* ── React hook example ── */
function useTooltip() {
  const [visible, setVisible] = useState(false);
  const ref = useRef(null);
  return {
    ref,
    visible,
    triggerProps: {
      onMouseEnter: () => setVisible(true),
      onMouseLeave: () => setVisible(false),
    },
  };
}

/* ── CSS tokens ── */
.dt-tooltip {
  position: absolute;
  background: var(--n7);
  color: #fff;
  padding: 8px 10px;
  border-radius: 6px;
  font: 400 12px/16px var(--font-sans);
  max-width: 200px;
  white-space: normal;
  pointer-events: none;
  z-index: 999;
  opacity: 0;
  visibility: hidden;
  transition: opacity .15s;
}
.dt-tooltip.visible {
  opacity: 1;
  visibility: visible;
}
/* Arrow (top placement) */
.dt-tooltip::after {
  content: '';
  position: absolute;
  top: 100%;
  left: 50%;
  transform: translateX(-50%);
  border: 5px solid transparent;
  border-top-color: var(--n7);
}
